clear;
clc;

% parameter
m = 0.063;
g = 9.81;
J = diag([0.0000582857, 0.0000716914, 0.0001]);
e3 = [0; 0; 1];

% 제어 게인
kR = 0.0005;    % attitude gain
kW = 0.0001;    % 각속도 게인

% 시뮬 설정
dt = 0.001;
T  = 5;

%%

% initial condition 
R = Ry(30 * pi/180);      % 초기 상태 = 30도 기울임
W = [0; 0; 0];    % 각속도: 정지
p = [0; 0; -1];   % 위치: NED 기준 고도 1m (z가 아래라 음수)
v = [0; 0; 0];    % 속도: 정지

%%
% 기록용 배열
steps = round(T/dt);
R_hist = zeros(3, 3, steps);
W_hist = zeros(3, steps);
p_hist = zeros(3, steps);

%%
% Simulation Loop
for i = 1:steps

  % Geometric Controller
  Rdes = eye(3);
  Wdes = [0; 0; 0];

  eR = Vhelper(0.5 * (Rdes'*R - R'*Rdes));
  eW = W - R'*Rdes*Wdes;

  tau = -kR*eR - kW*eW + cross(W, J*W);     % 비례 제어 + 미분 제어 + 자이로 보상
  f   = m*g / R(3,3);

  % 자세
  Wdot = J \ (tau - cross(W, J*W));
  W    = W + Wdot*dt;
  Rdot = R * Whelper(W);
  R    = R + Rdot*dt;
  R    = GSnorm(R);

  % 위치
  vdot = (m*g*e3 - f*R*e3) / m;
  v    = v + vdot*dt;
  p    = p + v*dt;

  %% 기록
  R_hist(:,:,i) = R;
  W_hist(:,i)   = W;
  p_hist(:,i)   = p;
end

%%
% 유틸 함수
function Wh = Whelper(W)
  Wh = [ 0    -W(3)  W(2);
         W(3)  0    -W(1);
        -W(2)  W(1)  0   ];
end

function Vh = Vhelper(M)
  Vh = [M(3,2); M(1,3); M(2,1)];
end

function B = GSnorm(A)
  B(:,1) = A(:,1) / norm(A(:,1));
  B(:,2) = A(:,2) - dot(B(:,1), A(:,2))*B(:,1);
  B(:,2) = B(:,2) / norm(B(:,2));
  B(:,3) = cross(B(:,1), B(:,2));
end

%%
function R = Ry(angle)
  R = [cos(angle)  0  sin(angle);
       0           1  0;
      -sin(angle)  0  cos(angle)];
end
%%
% 플롯
t = (0:steps-1) * dt;

figure; %[output:46e37079]
subplot(3,1,1); plot(t, p_hist(3,:)); %[output:46e37079]
xlabel('t'); ylabel('z [m]'); title('고도'); %[output:46e37079]

subplot(3,1,2); plot(t, W_hist'); %[output:46e37079]
xlabel('t'); ylabel('Ω [rad/s]'); title('각속도'); %[output:46e37079]
legend('p','q','r'); %[output:46e37079]

subplot(3,1,3); plot(t, squeeze(R_hist(3,3,:))); %[output:46e37079]
xlabel('t'); ylabel('R_{33}'); title('자세 (R33=1이면 수평)'); %[output:46e37079]


